import xml.etree.ElementTree as ET

def parse_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    settings = {}
    
    for child in root:
        key = child.tag
        value = child.text
        
        if value is not None:  # ignore empty tags
            settings[key] = value
            
    return settings